1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Simplest cases ---
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const out = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(out.results[0]).toEqual({ premium: 5 });
12	  });
13	
14	  // --- Base premiums for main items (each + 5 G fee) ---
15	  it("quote a plain sword → premium 105 G (100 base + 5 fee)", () => {
16	    const out = runScenario({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [{ op: "quote", items: [{ type: "sword" }] }],
19	    });
20	    expect(out.results[0]).toEqual({ premium: 105 });
21	  });
22	  it("quote a plain amulet → premium 65 G (60 base + 5 fee)", () => {
23	    const out = runScenario({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
26	    });
27	    expect(out.results[0]).toEqual({ premium: 65 });
28	  });
29	  it("quote a plain staff → premium 85 G (80 base + 5 fee)", () => {
30	    const out = runScenario({
31	      customer: { yearsWithMHPCO: 0 },
32	      steps: [{ op: "quote", items: [{ type: "staff" }] }],
33	    });
34	    expect(out.results[0]).toEqual({ premium: 85 });
35	  });
36	  it("quote a plain potion → premium 45 G (40 base + 5 fee)", () => {
37	    const out = runScenario({
38	      customer: { yearsWithMHPCO: 0 },
39	      steps: [{ op: "quote", items: [{ type: "potion" }] }],
40	    });
41	    expect(out.results[0]).toEqual({ premium: 45 });
42	  });
43	
44	  // --- Components and blocks ---
45	  it("quote 2 runes → 50 G base premium (55 with fee)", () => {
46	    const out = runScenario({
47	      customer: { yearsWithMHPCO: 0 },
48	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
49	    });
50	    expect(out.results[0]).toEqual({ premium: 55 });
51	  });
52	  it.todo("quote 3 runes → 60 G base premium block (65 with fee)");
53	  it.todo("quote 4 runes → 100 G base premium, no block (105 with fee)");
54	  it.todo("quote 7 runes → 175 G base premium (180 with fee)");
55	  it.todo("quote 2 runes + 1 moonstone → 75 G base premium (alike = same type)");
56	  it.todo("quote 3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
57	
58	  // --- Item-specific modifiers ---
59	  it.todo("cursed sword adds 50% surcharge on its base premium → 100 + 50 + 5 = 155 G");
60	  it.todo("sword with enchantment 5 adds 30% surcharge → 100 + 30 + 5 = 135 G");
61	  it.todo("sword with enchantment 4 has no high-enchantment surcharge → 105 G");
62	  it.todo("cursed sword with enchantment 5 has both surcharges → 100 + 50 + 30 + 5 = 185 G");
63	
64	  // --- Policy-wide modifiers ---
65	  it.todo("long-standing customer (≥ 2 years) gets 20% loyalty discount on policy base");
66	  it.todo("customer with exactly 2 years gets loyalty discount");
67	  it.todo("first insurance carries 10% initial assessment surcharge on policy base");
68	  it.todo("second contract gets 15% follow-up discount on policy base");
69	
70	  // --- Modifier scope on multi-item policies ---
71	  it.todo("cursed sword + plain amulet → 100 + 60 base + 50 curse + 5 fee = 215 G");
72	
73	  // --- Rounding ---
74	  it.todo("premium yielding 197.5 G rounds up to 198 G (MHPCO favor)");
75	
76	  // --- Integration examples ---
77	  it.todo("newcomer with cursed sword (0 years, no prev contract, ench 3) → 165 G");
78	  it.todo("long-standing customer's second cursed enchanted sword (3 yrs, ench 7) → 160 G");
79	
80	  // --- Claim: basic standard reimbursement ---
81	  it.todo("regular sword damage 500 G → payout 400 G (500 − 100 deductible)");
82	  it.todo("rune damage 200 G → payout 100 G (no special clause)");
83	
84	  // --- Claim: special clauses ---
85	  it.todo("dragon-material sword ench 9, damage 1000 G → payout 400 G (50% then deductible)");
86	  it.todo("dragon-material sword ench 5, damage 800 G → payout 700 G (full minus deductible)");
87	  it.todo("steel sword ench 9, damage 1000 G → payout 400 G (50% then deductible)");
88	  it.todo("dragon-material sword exactly ench 8, damage 1000 G → payout 400 G");
89	
90	  // --- Claim: per-damage-event deductible ---
91	  it.todo("dragon attack on sword (500) and amulet (300) → payout 600 G (deductible per item)");
92	
93	  // --- Claim: rounding ---
94	  it.todo("payout yielding 350.5 G rounds down to 350 G (MHPCO favor)");
95	
96	  // --- Claim: cap ---
97	  it.todo("policy of sword and amulet → insurance sum 1600 G, cap 3200 G");
98	  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value)");
99	  it.todo("sword + 3 runes (block) → insurance sum 1750 G (block affects premium only)");
100	  it.todo("sword 1500 G claim then 1500 G claim → payouts 1400, 600; cap 600 then 0");
101	
102	  // --- Multiple items of same type ---
103	  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
104	  it.todo("two sword damages on two-sword policy → each gets own deductible");
105	  it.todo("damages array has more entries of a type than policy covers → CLI errors");
106	
107	  // --- Edge cases / error handling ---
108	  it.todo("quote with unknown item type → CLI errors non-zero, stderr message, no results");
109	  it.todo("claim references item not in policy → CLI errors");
110	  it.todo("claim damage amount negative → CLI errors");
111	});
