1	const PROCESSING_FEE = 5;
2	
3	type Item = { type: string };
4	type QuoteStep = { op: "quote"; items: Item[] };
5	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
6	type StepResult = { premium: number };
7	type ScenarioResult = { results: StepResult[] };
8	
9	const BASE_PRICES: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	};
16	
17	const basePriceOf = (item: Item): number => BASE_PRICES[item.type] ?? 0;
18	
19	const sumBasePrices = (items: Item[]): number =>
20	  items.reduce((sum, item) => sum + basePriceOf(item), 0);
21	
22	const quotePremium = (items: Item[]): number =>
23	  sumBasePrices(items) + PROCESSING_FEE;
24	
25	export const runScenario = (input: Scenario): ScenarioResult => ({
26	  results: input.steps.map((step) => ({ premium: quotePremium(step.items) })),
27	});
